const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorstr = floor.toString().padStart(2, '0');
return {
    action: 'subscribe',
    topic: `campus/b01/f${floorstr}/+/telemetry`,
    qos: 0
};

let payload = msg.payload;
if (typeof payload === 'string') {
    try { payload = JSON.parse(payload); } catch (e) { return null; }
}

// Extract Device Name from Payload or Topic
// Topic format: campus/b01/fXX/rYYY/telemetry
let deviceName = payload.deviceName;
if (!deviceName && msg.topic) {
    const parts = msg.topic.split('/');
    if (parts.length >= 4) {
        deviceName = `b01-${parts[2]}-${parts[3]}`;
    }
}

if (!deviceName) return null;

// Normalize hvac_mode (engine sends lowercase, TB expects uppercase or consistent format)
const hvac = (payload.hvac_mode || payload.hvac_status || '').toUpperCase();

let values = {};
if (payload.security_alert) {
    values = {
        security_alert: payload.security_alert,
        room_id: payload.room_id || deviceName,
        alert_timestamp: payload.timestamp || Date.now()
    };
} else {
    values = {
        temperature: payload.temperature,
        humidity: payload.humidity,
        occupancy: payload.occupancy,
        light_level: payload.light_level,
        hvac_mode: hvac,
        hvac_status: hvac,
        lighting_dimmer: payload.lighting_dimmer,
        current_version: payload.current_version,
        alpha: payload.alpha,
        beta: payload.beta
    };
}

const telemetry = JSON.stringify({
    [deviceName]: [{
        ts: payload.timestamp ? payload.timestamp * 1000 : Date.now(),
        values: values
    }]
});

const connect = JSON.stringify({ device: deviceName });

return [
    { payload: telemetry },
    { payload: connect },
    { payload: payload },
    { payload: JSON.stringify({ [deviceName]: { polygonIndex: parseInt(deviceName.split('-r')[1]) % 20 } }) }
];

const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorOffset = (floor - 1) * 20;
const floorstr = floor.toString().padStart(2, '0');
const coapHost = env.get('COAP_HOST') || 'campus_engine';
for (let room = 1; room <= 20; room++) {
    const roomId = floorOffset + room;
    const port = 5700 + roomId - 1;
    node.send({
        url: `coap://${coapHost}:${port}/payload`,
        method: 'GET',
        roomId: `b01-f${floorstr}-r${roomId.toString().padStart(3, '0')}`
    });
}
return null;

let data;
if (typeof msg.payload === 'object' && !Buffer.isBuffer(msg.payload)) {
    data = msg.payload;
} else {
    const raw = Buffer.isBuffer(msg.payload) ? msg.payload.toString('utf8') : msg.payload;
    try {
        data = JSON.parse(raw);
    } catch (e) {
        node.error('CoAP JSON parse failed: ' + e.message, msg);
        return null;
    }
}

const deviceName = data.metadata ? data.metadata.sensor_id + '-COAP' : data.deviceName;
let values = {};

if (data.security_alert) {
    values = {
        security_alert: data.security_alert,
        room_id: data.room_id || deviceName,
        alert_timestamp: data.timestamp || Date.now()
    };
} else {
    const hvac = data.actuators.hvac_mode;
    values = {
        temperature: data.sensors.temperature,
        humidity: data.sensors.humidity,
        occupancy: data.sensors.occupancy,
        light_level: data.sensors.light_level,
        hvac_mode: hvac,
        hvac_status: hvac,
        lighting_dimmer: data.actuators.lighting_dimmer,
        current_version: data.metadata.version,
        alpha: data.metadata.alpha,
        beta: data.metadata.beta
    };
}

const telemetry = JSON.stringify({
    [deviceName]: [{
        ts: Date.now(),
        values: values
    }]
});

const connect = JSON.stringify({ device: deviceName });
const match = deviceName.match(/r(\d+)/i);
const roomNumber = (match ? parseInt(match[1], 10) : 0) % 20;
const attributes = JSON.stringify({
    [deviceName]: {
        polygonIndex: roomNumber
    }
});

return [
    { payload: telemetry },
    { payload: connect },
    { payload: data },
    { payload: attributes }
];

let rooms = flow.get("rooms") || Array.from({ length: 20 }, () => ({
    count: 0,
    temp_sum: 0,
    humidity_sum: 0,
    occupancy: 0,
    light_level: 0,
    hvac_mode: 'off',
    hvac_status: 'off',
    lighting_dimmer: 0
}));

const curr_room = (msg.payload.metadata.room - 1) % 20;
const room = rooms[curr_room];
const sensors = msg.payload.sensors || {};
const actuators = msg.payload.actuators || {};
const metadata = msg.payload.metadata || {};

room.count++;
room.temp_sum += Number(sensors.temperature || 0);
room.humidity_sum += Number(sensors.humidity || 0);
if (sensors.occupancy !== undefined) room.occupancy = sensors.occupancy;
if (sensors.light_level !== undefined) room.light_level = sensors.light_level;
if (actuators.hvac_mode !== undefined) {
    room.hvac_mode = actuators.hvac_mode;
    room.hvac_status = actuators.hvac_mode;
}
if (actuators.lighting_dimmer !== undefined) room.lighting_dimmer = actuators.lighting_dimmer;

// Config values - attached without averaging
if (metadata.alpha !== undefined) room.alpha = metadata.alpha;
if (metadata.beta !== undefined) room.beta = metadata.beta;
if (metadata.version !== undefined) room.version = metadata.version;

flow.set("rooms", rooms);
msg.payload = room;
return msg;

let rooms = flow.get("rooms") || Array.from({ length: 20 }, () => ({
    count: 0,
    temp_sum: 0,
    humidity_sum: 0,
    occupancy: 0,
    light_level: 0,
    hvac_mode: 'off',
    hvac_status: 'off',
    lighting_dimmer: 0
}));

const curr_room = (msg.payload.room - 1) % 20;
const room = rooms[curr_room];

room.count++;
room.temp_sum += Number(msg.payload.temperature || 0);
room.humidity_sum += Number(msg.payload.humidity || 0);
if (msg.payload.occupancy !== undefined) room.occupancy = msg.payload.occupancy;
if (msg.payload.light_level !== undefined) room.light_level = msg.payload.light_level;
if (msg.payload.hvac_mode !== undefined) {
    room.hvac_mode = msg.payload.hvac_mode;
    room.hvac_status = msg.payload.hvac_mode;
}
if (msg.payload.hvac_status !== undefined) room.hvac_status = msg.payload.hvac_status;
if (msg.payload.lighting_dimmer !== undefined) room.lighting_dimmer = msg.payload.lighting_dimmer;

// Config values - attached without averaging
if (msg.payload.alpha !== undefined) room.alpha = msg.payload.alpha;
if (msg.payload.beta !== undefined) room.beta = msg.payload.beta;
if (msg.payload.current_version !== undefined) room.version = msg.payload.current_version;

flow.set("rooms", rooms);
msg.payload = room;
return msg;

const floor = Number(env.get("FLOOR_NUMBER") || 0);
if (floor === 0) return null;
const floorOffset = (floor - 1) * 20;
const floorstr = floor.toString().padStart(2, '0');
let rooms = flow.get("rooms") || Array.from({ length: 20 }, () => ({
    count: 0,
    temp_sum: 0,
    humidity_sum: 0,
    occupancy: 0,
    light_level: 0,
    hvac_mode: 'off',
    hvac_status: 'off',
    lighting_dimmer: 0
}));

for (let i = 0; i < 20; i++) {
    const room = rooms[i];
    const count = room.count || 0;
    const roomId = floorOffset + i + 1;
    let deviceName;
    if(!(i%2)) {deviceName = `b01-f${floorstr}-r${roomId.toString().padStart(3, '0')}`}
    else { deviceName = `b01-f${floorstr}-r${roomId.toString().padStart(3, '0')}-COAP` }

    node.send({
        payload: JSON.stringify({
            [deviceName]: [
                {
                    ts: Date.now(),
                    values: {
                        temperature: count > 0 ? room.temp_sum / count : 0,
                        humidity: count > 0 ? room.humidity_sum / count : 0,
                        occupancy: room.occupancy,
                        light_level: room.light_level,
                        hvac_mode: room.hvac_mode,
                        hvac_status: room.hvac_status,
                        lighting_dimmer: room.lighting_dimmer,
                        alpha: room.alpha,
                        beta: room.beta,
                        current_version: room.version
                    }
                }
            ]
        })
    });
}

flow.set("rooms", undefined);
return null;

const floor = Number(env.get('FLOOR_NUMBER') || 0);

// Master (floor 0) has no TB gateway connection — it never receives these messages.
if (floor === 0) return null;

let payload = msg.payload;

// Handle v1/devices/me/attributes format (shared wrapper from TB server push)
if (payload && payload.shared) {
    payload = payload.shared;
    msg.payload = payload;
}
// Handle legacy v1/gateway/attributes format (child device attr notification)
else if (payload && payload.device && payload.data) {
    payload = payload.data;
    msg.payload = payload;
    msg.deviceName = payload.device;
}

// 1. Basic validation
const required = ["config_data", "signature", "target_version", "target"];
if (!required.every(k => payload.hasOwnProperty(k))) return null;

// Also ignore empty config_data (initial provisioning default)
if (!payload.config_data) return null;

const target = payload.target;
const floorPad = String(floor).padStart(2, '0');

// 2. Responsibility Check — each worker handles its own floor only.
if (target === "all") {
    // Re-target to this floor so each worker covers its 20 rooms independently.
    // Avoids 10 identical broadcast messages hitting every room.
    msg.payload = Object.assign({}, payload, { target: `floor_${floorPad}` });
} else if (target.startsWith("floor_")) {
    const targetFloor = parseInt(target.split("_")[1], 10);
    if (floor !== targetFloor) return null;
} else if (target.startsWith("b01-f")) {
    const targetFloor = parseInt(target.substring(5, 7), 10);
    if (floor !== targetFloor) return null;
} else {
    return null;
}

return msg;

// msg.payload comes from the engine OTA ack:
// { deviceName: 'b01-f01-r001', current_version: '2.0' }
const p = msg.payload;
if (!p || !p.deviceName || !p.current_version) return null;

// Track floor-level ack count in flow context for widget progress
const countKey = 'ota_acked_' + p.current_version;
const count = (flow.get(countKey) || 0) + 1;
flow.set(countKey, count);

// Output 1: Update child device telemetry via TB gateway protocol
const msg1 = Object.assign({}, msg, {
    topic: 'v1/gateway/telemetry',
    payload: JSON.stringify({
        [p.deviceName]: [{
            ts: Date.now(),
            values: { current_version: p.current_version }
        }]
    })
});

// Output 2: Publish this floor's cumulative ack count as own device telemetry
const msg2 = {
    payload: JSON.stringify({
        ota_floor_acked: count,
        ota_acked_version: p.current_version
    })
};

return [msg1, msg2];

let body = msg.payload;
let deviceName = body.device;
let data = body.data || {};
if (data.shared) {
    // ThingsBoard gateway may wrap shared attrs under data.shared
    data = data.shared;
}
if (!deviceName) return null;

let cmdPayload = null;
let topic = null;
const deviceMatch = deviceName.match(/^b01-f(\d{2})-r(\d{3})$/);
if (!deviceMatch) return null;

if (data.hvac_command) {
    cmdPayload = { hvac_mode: data.hvac_command };
    topic = `campus/b01/cmd/${deviceName}`;
} else if (data.dimmer_command) {
    cmdPayload = { lighting_dimmer: parseInt(data.dimmer_command, 10) };
    topic = `campus/b01/f${deviceMatch[1]}/r${deviceMatch[2]}/actuator/light_dimmer`;
}
if (!cmdPayload) return null;

node.log(`Attr for ${deviceName} -> ${topic}: ${JSON.stringify(cmdPayload)}`);

return {
    topic: topic,
    payload: JSON.stringify({
        ...cmdPayload,
        device_name: deviceName,
        transport: 'mqtt'
    })
};

const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorPad = String(floor).padStart(2, '0');

let payload = msg.payload;
if (payload && payload.shared) {
    payload = payload.shared;
}

let messages = [];

for (let key in payload) {
    const match = key.match(/^(hvac_mode|target_temp|lighting_dimmer)_r(\d+)$/);
    if (match) {
        const cmdType = match[1];
        const roomNum = match[2];
        const value = payload[key];

        const roomIndex = parseInt(roomNum, 10);
        const floorOffset = (floor - 1) * 20;
        const realRoomNum = floorOffset + roomIndex;
        const realRoomStr = String(realRoomNum).padStart(3, '0');

        let deviceName = `b01-f${floorPad}-r${realRoomStr}`;
        if ((roomIndex - 1) % 2 !== 0) {
            deviceName += "-COAP";
        }

        let cmdPayload = {};
        let topic = `campus/b01/cmd/${deviceName}`;

        if (cmdType === 'hvac_mode') {
            cmdPayload = { hvac_mode: value };
        } else if (cmdType === 'target_temp') {
            cmdPayload = { target_temp: value };
        } else if (cmdType === 'lighting_dimmer') {
            cmdPayload = { lighting_dimmer: value };
            topic = `campus/b01/f${floorPad}/r${realRoomStr}/actuator/light_dimmer`;
        }

        node.log(`Floor Attr for ${key} -> ${deviceName}: ${JSON.stringify(cmdPayload)}`);

        messages.push({
            topic: topic,
            payload: JSON.stringify({
                ...cmdPayload,
                device_id: deviceName,
                transport: deviceName.includes('COAP') ? 'coap' : 'mqtt'
            })
        });
    }
}

return [messages];

const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorstr = floor.toString().padStart(2, '0');
return {
    action: 'subscribe',
    topic: `campus/b01/cmd/f${floorstr}/+`,
    qos: 1
};

const topic = msg.topic || '';
const match = topic.match(/^campus\/b01\/cmd\/f(\d{2})\/r(\d{3})$/);
if (!match) return null;

let payload = msg.payload;
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.error('Command payload parse failed: ' + e.message, msg);
        return null;
    }
}

const floorNum = parseInt(match[1], 10);
const roomNum = parseInt(match[2], 10);
const transport = payload.transport || 'mqtt';
const deviceName = payload.device_name || `b01-f${match[1]}-r${match[2]}`;
const commandId = payload.command_id;
if (!commandId) {
    node.error('Missing command_id for floor command', msg);
    return null;
}

const pending = flow.get('pendingRpcAcks') || {};
const state = pending[commandId];
if (!state) {
    node.warn(`No pending RPC state for command_id ${commandId}`);
    return null;
}

if (transport === 'coap') {
    return [null, {
        topic,
        payload,
        floorNum,
        roomNum,
        deviceName,
        _rpc: {
            commandId,
            deviceName: state.deviceName,
            rpcId: state.rpcId,
            startedAt: state.startedAt,
            requested: state.requested
        }
    }];
}

return [{
    topic: `campus/b01/cmd/${deviceName}`,
    payload: JSON.stringify({
        ...payload,
        command_id: commandId
    })
}, null];

const roomNum = Number(msg.roomNum);
if (!roomNum) return null;

const payload = msg.payload || {};
const coapHost = env.get('COAP_HOST') || 'campus_engine';
const cmdPayload = {};
let actuator = null;
if (payload.hvac_mode !== undefined) {
    cmdPayload.hvac_mode = payload.hvac_mode;
    actuator = 'hvac';
}
if (payload.lighting_dimmer !== undefined) {
    cmdPayload.lighting_dimmer = payload.lighting_dimmer;
    actuator = 'light_dimmer';
}
if (!actuator) return null;

msg.url = `coap://${coapHost}:${5700 + roomNum - 1}/actuator/${actuator}`;
msg.method = 'PUT';
msg.payload = cmdPayload;
return msg;

const floor = Number(env.get('FLOOR_NUMBER') || 0);
if (floor === 0) return null;
const floorstr = floor.toString().padStart(2, '0');

// Subscribe to all ACKs for THIS floor
node.send({ action: 'subscribe', topic: `campus/b01/f${floorstr}/+/ack/hvac_applied`, qos: 1 });
node.send({ action: 'subscribe', topic: `campus/b01/f${floorstr}/+/ack/light_dimmer_applied`, qos: 1 });
node.log(`Subscribed to ACKs for floor ${floorstr}`);
return null;

let payload = msg.payload;
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.error('MQTT ack parse failed: ' + e.message, msg);
        return null;
    }
}

const commandId = payload && payload.command_id;
if (!commandId) return null;

const pending = flow.get('pendingRpcAcks') || {};
const state = pending[commandId];
if (!state) return null;

delete pending[commandId];
flow.set('pendingRpcAcks', pending);

const rttMs = Date.now() - state.startedAt;
const ackValues = {
    rtt_ms: rttMs
};
if (payload.hvac_mode !== undefined) {
    ackValues.hvac_mode = String(payload.hvac_mode).toLowerCase();
    ackValues.hvac_status = String(payload.hvac_mode).toLowerCase();
}
if (payload.lighting_dimmer !== undefined) {
    ackValues.lighting_dimmer = payload.lighting_dimmer;
}
if (state.requested !== undefined) {
    ackValues.requested_value = state.requested;
}

return [
    {
        payload: JSON.stringify({
            device: state.deviceName,
            id: state.rpcId,
            data: {
                success: true,
                state: payload.hvac_mode !== undefined ? String(payload.hvac_mode).toLowerCase() : payload.lighting_dimmer,
                rtt_ms: rttMs,
                ack: payload
            }
        })
    },
    {
        payload: JSON.stringify({
            [state.deviceName]: [
                {
                    ts: Date.now(),
                    values: ackValues
                }
            ]
        })
    },
    {
        payload: {
            source: 'mqtt-ack',
            command_id: commandId,
            device: state.deviceName,
            rtt_ms: rttMs,
            ack: payload
        }
    }
];

const floor = Number(env.get('FLOOR_NUMBER') || 0);
let body = msg.payload;
if (typeof body === 'string') {
    try { body = JSON.parse(body); } catch (e) { return null; }
}
const rpcData = body.data || body || {};
const method = rpcData.method;
const params = rpcData.params || {};
const rpcId = body.id || rpcData.id;
const fullDeviceName = body.device || params.device || msg.topic.split('/').pop();
if (!fullDeviceName || rpcId === undefined) return null;

const isCoap = fullDeviceName.endsWith('-COAP');
const deviceName = isCoap ? fullDeviceName.replace(/-COAP$/, '') : fullDeviceName;
const deviceMatch = deviceName.match(/^b01-f(\d{2})-r(\d{3})$/);
if (!deviceMatch) return null;

let cmdPayload = null;
let topic = null;
let ackTopic = null;
let coapPath = null;

if (method === 'hvac' || method === 'hvac_mode') {
    const mode = typeof params === 'object' ? (params.hvac_mode || params.params) : params;
    cmdPayload = { hvac_mode: mode };
    topic = `campus/b01/cmd/${deviceName}`;
    coapPath = 'actuator/hvac';
    ackTopic = 'hvac_applied';
} else if (method === 'light_dimmer' || method === 'lighting_dimmer') {
    const val = typeof params === 'object' ? (params.lighting_dimmer || params.params) : params;
    cmdPayload = { lighting_dimmer: parseInt(val, 10) };
    topic = `campus/b01/f${deviceMatch[1]}/r${deviceMatch[2]}/actuator/light_dimmer`;
    coapPath = 'actuator/light_dimmer';
    ackTopic = 'light_dimmer_applied';
}
if (!cmdPayload) return null;

const commandId = `${deviceName}:${rpcId}`;
const pending = flow.get('pendingRpcAcks') || {};
pending[commandId] = {
    deviceName: fullDeviceName,
    rpcId,
    startedAt: Date.now(),
    requested: Object.values(cmdPayload)[0],
    ackTopic
};
flow.set('pendingRpcAcks', pending);

const result = {
    payload: JSON.stringify({
        ...cmdPayload,
        command_id: commandId,
        rpc_id: rpcId,
        device_name: deviceName,
        transport: isCoap ? 'coap' : 'mqtt'
    })
};

if (isCoap) {
    const coapHost = env.get('COAP_HOST') || 'campus_engine';
    const roomNum = parseInt(deviceMatch[2], 10);
    const floorOffset = (floor - 1) * 20;
    const port = 5700 + floorOffset + roomNum - 1;
    result.url = `coap://${coapHost}:${port}/${coapPath}`;
    return [null, result];
} else {
    result.topic = topic;
    return [result, null];
}

const rpc = msg._rpc;
if (!rpc || !rpc.commandId) return null;

let payload = msg.payload;
if (Buffer.isBuffer(payload)) {
    payload = payload.toString('utf8');
}
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.error('CoAP ack parse failed: ' + e.message, msg);
        return null;
    }
}

const pending = flow.get('pendingRpcAcks') || {};
delete pending[rpc.commandId];
flow.set('pendingRpcAcks', pending);

const rttMs = Date.now() - rpc.startedAt;
const ackValues = { rtt_ms: rttMs };
if (payload.hvac_mode !== undefined) {
    ackValues.hvac_mode = String(payload.hvac_mode).toLowerCase();
    ackValues.hvac_status = String(payload.hvac_mode).toLowerCase();
}
if (payload.lighting_dimmer !== undefined) {
    ackValues.lighting_dimmer = payload.lighting_dimmer;
}
if (payload.ambient !== undefined) {
    ackValues.light_level = payload.ambient;
}
if (rpc.requested !== undefined) {
    ackValues.requested_value = rpc.requested;
}

return [
    {
        payload: JSON.stringify({
            device: rpc.deviceName,
            id: rpc.rpcId,
            data: {
                success: true,
                state: payload.hvac_mode !== undefined ? String(payload.hvac_mode).toLowerCase() : payload.lighting_dimmer,
                rtt_ms: rttMs,
                ack: payload
            }
        })
    },
    {
        payload: JSON.stringify({
            [rpc.deviceName]: [
                {
                    ts: Date.now(),
                    values: ackValues
                }
            ]
        })
    },
    {
        payload: {
            source: 'coap-ack',
            command_id: rpc.commandId,
            device: rpc.deviceName,
            rtt_ms: rttMs,
            ack: payload
        }
    }
];
